	plans []BranchPlan,
) map[plumbing.ReferenceName]DesiredRef {
	out := make(map[plumbing.ReferenceName]DesiredRef, len(plans))
	for _, plan := range plans {
		if ref, ok := desired[plan.TargetRef]; ok {
