func adaptiveNextProbeSpan(limit int64, measuredBytes int, selectedSpan int, remaining int) int {
	if selectedSpan < 1 {
		selectedSpan = 1
	}
	if remaining < 1 {
		return selectedSpan
	}
	if limit <= 0 || measuredBytes <= 0 {
		if selectedSpan > remaining {
			return remaining
		}
		return selectedSpan
	}

	next := int((int64(selectedSpan) * limit) / int64(measuredBytes))
	if next < 1 {
		next = 1
	}
	if next > remaining {
		next = remaining
	}

